/**
 * Order validators — pure validation functions for order operations.
 *
 * These are stateless, side-effect-free functions extracted from OrderService.
 * They validate inputs and business rules without touching the database.
 */

import type { CreateOrderInput, OrderStatus } from '../models/order.js';

/**
 * Valid status transitions for the order lifecycle.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Validate the input for creating a new order.
 * Throws if the input is invalid.
 */
export function validateCreateOrderInput(input: CreateOrderInput): void {
  if (input.items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * User validators — pure validation functions for user operations.
 *
 * These are stateless, side-effect-free functions extracted from UserService.
 * They validate inputs and compute change sets without touching the database.
 */

import type { User, UpdateUserInput } from '../models/user.js';

/**
 * Detect which fields changed between an update input and the existing user.
 * Returns an array of changed field names.
 */
export function detectUserChanges(input: UpdateUserInput, existing: User): string[] {
  const changes: string[] = [];
  if (input.name && input.name !== existing.name) changes.push('name');
  if (input.email && input.email !== existing.email) changes.push('email');
  if (input.role && input.role !== existing.role) changes.push('role');
  return changes;
}

/**
 * Check whether the update input is requesting an email change.
 */
export function isEmailChanging(input: UpdateUserInput, existing: User): boolean {
  return !!(input.email && input.email !== existing.email);
}

/**
 * Notification validators — pure validation functions for notification preferences.
 *
 * Extracted from PreferencesService.shouldSendNotification(). These functions
 * check user preferences without any side effects or data store access.
 */

import type { NotificationType } from '../models/notification.js';
import type { UserNotificationPreferences } from '../models/user-preferences.js';

/**
 * Result of a notification preference check.
 * When `allowed` is false, `reason` explains why.
 */
export interface NotificationCheckResult {
  allowed: boolean;
  reason?: string;
}

/**
 * Check whether a notification should be sent based on user preferences.
 *
 * Rules:
 * 1. Non-email channels are always allowed (only email preferences exist).
 * 2. Global emailEnabled must be true.
 * 3. Per-category subscription must not be explicitly false (missing = enabled).
 * 4. Email frequency must be 'immediate' for instant delivery.
 */
export function checkNotificationPreferences(
  prefs: UserNotificationPreferences,
  type: NotificationType,
  channel: string,
): NotificationCheckResult {
  if (channel !== 'email') {
    return { allowed: true };
  }

  if (!prefs.emailEnabled) {
    return { allowed: false, reason: 'email disabled' };
  }

  const categoryEnabled = prefs.categorySubscriptions[type];
  if (categoryEnabled === false) {
    return { allowed: false, reason: `category '${type}' unsubscribed` };
  }

  if (prefs.emailFrequency !== 'immediate') {
    return { allowed: false, reason: `frequency is ${prefs.emailFrequency}` };
  }

  return { allowed: true };
}

