import { describe, it, expect } from 'vitest';
import {
  validateCreateOrderInput,
  isValidStatusTransition,
} from '../../src/validators/order.validator.js';
import type { OrderStatus } from '../../src/models/order.js';

describe('order.validator', () => {
  describe('validateCreateOrderInput', () => {
    it('should accept input with items', () => {
      expect(() =>
        validateCreateOrderInput({
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        }),
      ).not.toThrow();
    });

    it('should throw for empty items', () => {
      expect(() =>
        validateCreateOrderInput({ userId: 'user-1', items: [] }),
      ).toThrow('Order must have at least one item');
    });

    it('should accept input with multiple items', () => {
      expect(() =>
        validateCreateOrderInput({
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
        }),
      ).not.toThrow();
    });
  });

  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const status of statuses) {
        expect(isValidStatusTransition('delivered', status)).toBe(false);
      }
    });

    it('should reject cancelled -> any', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const status of statuses) {
        expect(isValidStatusTransition('cancelled', status)).toBe(false);
      }
    });

    it('should cover the full valid lifecycle', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  detectUserChanges,
  isEmailChanging,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const baseUser: User = {
  id: 'user-1',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
};

describe('user.validator', () => {
  describe('detectUserChanges', () => {
    it('should detect name change', () => {
      const changes = detectUserChanges({ name: 'Bob' }, baseUser);
      expect(changes).toEqual(['name']);
    });

    it('should detect email change', () => {
      const changes = detectUserChanges({ email: 'bob@example.com' }, baseUser);
      expect(changes).toEqual(['email']);
    });

    it('should detect role change', () => {
      const changes = detectUserChanges({ role: 'admin' }, baseUser);
      expect(changes).toEqual(['role']);
    });

    it('should detect multiple changes', () => {
      const changes = detectUserChanges(
        { name: 'Bob', email: 'bob@example.com', role: 'admin' },
        baseUser,
      );
      expect(changes).toEqual(['name', 'email', 'role']);
    });

    it('should return empty array when nothing changed', () => {
      const changes = detectUserChanges({}, baseUser);
      expect(changes).toEqual([]);
    });

    it('should return empty array when values are the same', () => {
      const changes = detectUserChanges(
        { name: 'Alice', email: 'alice@example.com', role: 'member' },
        baseUser,
      );
      expect(changes).toEqual([]);
    });
  });

  describe('isEmailChanging', () => {
    it('should return true when email is different', () => {
      expect(isEmailChanging({ email: 'bob@example.com' }, baseUser)).toBe(true);
    });

    it('should return false when email is the same', () => {
      expect(isEmailChanging({ email: 'alice@example.com' }, baseUser)).toBe(false);
    });

    it('should return false when no email in input', () => {
      expect(isEmailChanging({}, baseUser)).toBe(false);
    });

    it('should return false when email is undefined', () => {
      expect(isEmailChanging({ name: 'Bob' }, baseUser)).toBe(false);
    });
  });
});

import { describe, it, expect } from 'vitest';
import { checkNotificationPreferences } from '../../src/validators/notification.validator.js';
import type { UserNotificationPreferences } from '../../src/models/user-preferences.js';
import { getDefaultPreferences } from '../../src/models/user-preferences.js';

describe('notification.validator', () => {
  describe('checkNotificationPreferences', () => {
    it('should allow notifications with default preferences', () => {
      const prefs = getDefaultPreferences('user-1');
      const result = checkNotificationPreferences(prefs, 'order-confirmation', 'email');
      expect(result.allowed).toBe(true);
      expect(result.reason).toBeUndefined();
    });

    it('should allow non-email channels regardless of preferences', () => {
      const prefs: UserNotificationPreferences = {
        ...getDefaultPreferences('user-1'),
        emailEnabled: false,
      };
      const result = checkNotificationPreferences(prefs, 'order-confirmation', 'sms');
      expect(result.allowed).toBe(true);
    });

    it('should block when email is disabled', () => {
      const prefs: UserNotificationPreferences = {
        ...getDefaultPreferences('user-1'),
        emailEnabled: false,
      };
      const result = checkNotificationPreferences(prefs, 'order-confirmation', 'email');
      expect(result.allowed).toBe(false);
      expect(result.reason).toBe('email disabled');
    });

    it('should block when category is unsubscribed', () => {
      const prefs: UserNotificationPreferences = {
        ...getDefaultPreferences('user-1'),
        categorySubscriptions: { 'order-confirmation': false },
      };
      const result = checkNotificationPreferences(prefs, 'order-confirmation', 'email');
      expect(result.allowed).toBe(false);
      expect(result.reason).toBe("category 'order-confirmation' unsubscribed");
    });

    it('should allow when category is explicitly subscribed', () => {
      const prefs: UserNotificationPreferences = {
        ...getDefaultPreferences('user-1'),
        categorySubscriptions: { 'order-confirmation': true },
      };
      const result = checkNotificationPreferences(prefs, 'order-confirmation', 'email');
      expect(result.allowed).toBe(true);
    });

    it('should allow when category is not in subscriptions (missing = enabled)', () => {
      const prefs = getDefaultPreferences('user-1');
      const result = checkNotificationPreferences(prefs, 'order-status-update', 'email');
      expect(result.allowed).toBe(true);
    });

    it('should block when email frequency is daily-digest', () => {
      const prefs: UserNotificationPreferences = {
        ...getDefaultPreferences('user-1'),
        emailFrequency: 'daily-digest',
      };
      const result = checkNotificationPreferences(prefs, 'order-confirmation', 'email');
      expect(result.allowed).toBe(false);
      expect(result.reason).toBe('frequency is daily-digest');
    });

    it('should block when email frequency is weekly-digest', () => {
      const prefs: UserNotificationPreferences = {
        ...getDefaultPreferences('user-1'),
        emailFrequency: 'weekly-digest',
      };
      const result = checkNotificationPreferences(prefs, 'order-confirmation', 'email');
      expect(result.allowed).toBe(false);
      expect(result.reason).toBe('frequency is weekly-digest');
    });

    it('should check emailEnabled before category', () => {
      const prefs: UserNotificationPreferences = {
        ...getDefaultPreferences('user-1'),
        emailEnabled: false,
        categorySubscriptions: { 'order-confirmation': false },
      };
      const result = checkNotificationPreferences(prefs, 'order-confirmation', 'email');
      expect(result.reason).toBe('email disabled');
    });

    it('should check category before frequency', () => {
      const prefs: UserNotificationPreferences = {
        ...getDefaultPreferences('user-1'),
        categorySubscriptions: { 'order-confirmation': false },
        emailFrequency: 'daily-digest',
      };
      const result = checkNotificationPreferences(prefs, 'order-confirmation', 'email');
      expect(result.reason).toBe("category 'order-confirmation' unsubscribed");
    });
  });
});
